9529 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
9530 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
9531 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
9532 /// instruction.
9533 static std::optional<bool>
9534 isImpliedCondAndOr(const Instruction *LHS, CmpPredicate RHSPred,
9535                    const Value *RHSOp0, const Value *RHSOp1,
9536                    const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9537   // The LHS must be an 'or', 'and', or a 'select' instruction.
9538   assert((LHS->getOpcode() == Instruction::And ||
9539           LHS->getOpcode() == Instruction::Or ||
9540           LHS->getOpcode() == Instruction::Select) &&
9541          "Expected LHS to be 'and', 'or', or 'select'.");
9542 
9543   assert(Depth <= MaxAnalysisRecursionDepth && "Hit recursion limit");
9544 
9545   // If the result of an 'or' is false, then we know both legs of the 'or' are
9546   // false.  Similarly, if the result of an 'and' is true, then we know both
9547   // legs of the 'and' are true.
9548   const Value *ALHS, *ARHS;
9549   if ((!LHSIsTrue && match(LHS, m_LogicalOr(m_Value(ALHS), m_Value(ARHS)))) ||
9550       (LHSIsTrue && match(LHS, m_LogicalAnd(m_Value(ALHS), m_Value(ARHS))))) {
9551     // FIXME: Make this non-recursion.
9552     if (std::optional<bool> Implication = isImpliedCondition(
9553             ALHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9554       return Implication;
9555     if (std::optional<bool> Implication = isImpliedCondition(
9556             ARHS, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue, Depth + 1))
9557       return Implication;
9558     return std::nullopt;
9559   }
9560   return std::nullopt;
9561 }
