9655 // condition dominating ContextI or nullptr, if no condition is found.
9656 static std::pair<Value *, bool>
9657 getDomPredecessorCondition(const Instruction *ContextI) {
9658   if (!ContextI || !ContextI->getParent())
9659     return {nullptr, false};
9660 
9661   // TODO: This is a poor/cheap way to determine dominance. Should we use a
9662   // dominator tree (eg, from a SimplifyQuery) instead?
9663   const BasicBlock *ContextBB = ContextI->getParent();
9664   const BasicBlock *PredBB = ContextBB->getSinglePredecessor();
9665   if (!PredBB)
9666     return {nullptr, false};
9667 
9668   // We need a conditional branch in the predecessor.
9669   Value *PredCond;
9670   BasicBlock *TrueBB, *FalseBB;
9671   if (!match(PredBB->getTerminator(), m_Br(m_Value(PredCond), TrueBB, FalseBB)))
9672     return {nullptr, false};
