3889 bool ICmpInst::isImpliedTrueByMatchingCmp(CmpPredicate Pred1,
3890                                           CmpPredicate Pred2) {
3891   // If the predicates match, then we know the first condition implies the
3892   // second is true.
3893   if (CmpPredicate::getMatching(Pred1, Pred2))
3894     return true;
3895 
3896   if (Pred1.hasSameSign() && CmpInst::isSigned(Pred2))
3897     Pred1 = ICmpInst::getFlippedSignednessPredicate(Pred1);
3898   else if (Pred2.hasSameSign() && CmpInst::isSigned(Pred1))
3899     Pred2 = ICmpInst::getFlippedSignednessPredicate(Pred2);
3900 
3901   switch (Pred1) {
3902   default:
3903     break;
3904   case ICMP_EQ:
3905     // A == B implies A >=u B, A <=u B, A >=s B, and A <=s B are true.
3906     return Pred2 == ICMP_UGE || Pred2 == ICMP_ULE || Pred2 == ICMP_SGE ||
3907            Pred2 == ICMP_SLE;
3908   case ICMP_UGT: // A >u B implies A != B and A >=u B are true.
3909     return Pred2 == ICMP_NE || Pred2 == ICMP_UGE;
3910   case ICMP_ULT: // A <u B implies A != B and A <=u B are true.
3911     return Pred2 == ICMP_NE || Pred2 == ICMP_ULE;
3912   case ICMP_SGT: // A >s B implies A != B and A >=s B are true.
3913     return Pred2 == ICMP_NE || Pred2 == ICMP_SGE;
3914   case ICMP_SLT: // A <s B implies A != B and A <=s B are true.
3915     return Pred2 == ICMP_NE || Pred2 == ICMP_SLE;
3916   }
3917   return false;
