9447   // to L0/R0.
9448   if (L0 == R1) {
9449     std::swap(R0, R1);
9450     RPred = ICmpInst::getSwappedCmpPredicate(RPred);
9451   }
9452   if (R0 == L1) {
9453     std::swap(L0, L1);
9454     LPred = ICmpInst::getSwappedCmpPredicate(LPred);
9455   }
9456   if (L1 == R1) {
