9563 std::optional<bool>
9564 llvm::isImpliedCondition(const Value *LHS, CmpPredicate RHSPred,
9565                          const Value *RHSOp0, const Value *RHSOp1,
9566                          const DataLayout &DL, bool LHSIsTrue, unsigned Depth) {
9567   // Bail out when we hit the limit.
9568   if (Depth == MaxAnalysisRecursionDepth)
9569     return std::nullopt;
9570 
9571   // A mismatch occurs when we compare a scalar cmp to a vector cmp, for
9572   // example.
9573   if (RHSOp0->getType()->isVectorTy() != LHS->getType()->isVectorTy())
9574     return std::nullopt;
9575 
9576   assert(LHS->getType()->isIntOrIntVectorTy(1) &&
9577          "Expected integer type only!");
9578 
9579   // Match not
9580   if (match(LHS, m_Not(m_Value(LHS))))
9581     LHSIsTrue = !LHSIsTrue;
9582 
9583   // Both LHS and RHS are icmps.
9584   const ICmpInst *LHSCmp = dyn_cast<ICmpInst>(LHS);
9585   if (LHSCmp)
9586     return isImpliedCondICmps(LHSCmp, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue);
9587 
9588   /// The LHS should be an 'or', 'and', or a 'select' instruction.  We expect
9589   /// the RHS to be an icmp.
9590   /// FIXME: Add support for and/or/select on the RHS.
9591   if (const Instruction *LHSI = dyn_cast<Instruction>(LHS)) {
9592     if ((LHSI->getOpcode() == Instruction::And ||
9593          LHSI->getOpcode() == Instruction::Or ||
9594          LHSI->getOpcode() == Instruction::Select))
9595       return isImpliedCondAndOr(LHSI, RHSPred, RHSOp0, RHSOp1, DL, LHSIsTrue,
9596                                 Depth);
9597   }
9598   return std::nullopt;
9599 }
