9678   assert((TrueBB == ContextBB || FalseBB == ContextBB) &&
9679          "Predecessor block does not point to successor?");
9680 
9681   // Is this condition implied by the predecessor condition?
9682   return {PredCond, TrueBB == ContextBB};
